import sys
from itertools import combinations

def main():
    N, M = map(int, sys.stdin.readline().split())
    stands = [sys.stdin.readline().strip() for _ in range(N)]

    # Generate all possible combinations of stands
    for k in range(1, N + 1):
        for combo in combinations(stands, k):
            covered = set()
            for s in combo:
                for j in range(M):
                    if s[j] == 'o':
                        covered.add(j)
            if len(covered) == M:
                print(k)
                return

if __name__ == "__main__":
    main()
